// ── Display labels (first letter used for fallback) ──

const PROVIDER_LABELS: Record<string, string> = {
  google: "Google",
  apple: "Apple",
  authentik: "Homelab",
  strava: "Strava",
  wahoo: "Wahoo",
  fitbit: "Fitbit",
  "ride-with-gps": "Ride with GPS",
  withings: "Withings",
  garmin: "Garmin",
  polar: "Polar",
  whoop: "WHOOP",
  peloton: "Peloton",
  oura: "Oura",
  zwift: "Zwift",
  suunto: "Suunto",
  trainerroad: "TrainerRoad",
  komoot: "Komoot",
  concept2: "Concept2",
  coros: "COROS",
  "cycling-analytics": "Cycling Analytics",
  cycling_analytics: "Cycling Analytics",
  decathlon: "Decathlon",
  "eight-sleep": "Eight Sleep",
  fatsecret: "FatSecret",
  mapmyfitness: "MapMyFitness",
  ultrahuman: "Ultrahuman",
  velohero: "VeloHero",
  wger: "Wger",
  xert: "Xert",
  "apple-health": "Apple Health",
  "strong-csv": "Strong",
  "cronometer-csv": "Cronometer",
};

export function providerLabel(id: string): string {
  return PROVIDER_LABELS[id] ?? id;
}

export function ProviderLogo({ provider, size = 20, className = "" }: ProviderLogoProps) {
  const path = SVG_PATHS[provider];
  const color = BRAND_COLORS[provider] ?? "#71717a";

  if (path) {
    return (
      <svg
        viewBox="0 0 24 24"
        width={size}
        height={size}
        fill={color}
        className={`shrink-0 ${className}`}
        aria-hidden="true"
      >
        <path d={path} />
      </svg>
    );
  }

  // Styled letter fallback
  const label = PROVIDER_LABELS[provider] ?? provider;
  const letter = label[0]?.toUpperCase() ?? "?";
  const fontSize = Math.round(size * 0.55);

  return (
    <span
      className={`inline-flex items-center justify-center rounded shrink-0 ${className}`}
      style={{
        width: size,
        height: size,
        backgroundColor: color,
        color: "#fff",
        fontSize,
        fontWeight: 600,
        lineHeight: 1,
      }}
      aria-hidden="true"
    >
      {letter}
    </span>
  );
}
